#!/bin/sh
# Generated by provision/centralized.py — Nextcloud setup for a family Cove.
occ() { php /var/www/html/occ "$@"; }
occ config:system:set skeletondirectory --value="" >/dev/null 2>&1 || true
for app in calendar notes contacts tasks; do
  occ app:install "$app" >/dev/null 2>&1 || occ app:enable "$app" >/dev/null 2>&1 || true
done
occ app:disable photos >/dev/null 2>&1 || true
